package main

import "fmt"

type Car struct {
	Brand string
	Model string
	Year  int
}

// Car struct'ina method ekleme
func (c Car) DisplayInfo() {
	fmt.Println(c.Year, c.Brand, c.Model)
}

func (c Car) GetAge(currentYear int) int {
	return currentYear - c.Year
}

func main() {
	car1 := Car{Brand: "Toyota", Model: "Corolla", Year: 2020}
	car2 := Car{Brand: "Honda", Model: "Civic", Year: 2018}

	fmt.Println("Araba bilgileri:")
	car1.DisplayInfo()
	car2.DisplayInfo()

	fmt.Println("\nArac yaslari (2026'ya gore):")
	fmt.Println("Car1 yasi:", car1.GetAge(2026), "yil")
	fmt.Println("Car2 yasi:", car2.GetAge(2026), "yil")

	// Struct slice
	cars := []Car{car1, car2, {Brand: "Ford", Model: "Focus", Year: 2022}}
	fmt.Println("\nTum arabalar:")
	for _, c := range cars {
		c.DisplayInfo()
	}
}
